import{_ as s,o as i,c as t,a2 as n}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"用启发式原则分析事实与推断","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/deconstruction/06-heuristics-facts-inferences.md","filePath":"03-interaction-design/notes/deconstruction/06-heuristics-facts-inferences.md","lastUpdated":1784248569000}'),e={name:"03-interaction-design/notes/deconstruction/06-heuristics-facts-inferences.md"};function l(r,a,h,d,p,o){return i(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="用启发式原则分析事实与推断" tabindex="-1">用启发式原则分析事实与推断 <a class="header-anchor" href="#用启发式原则分析事实与推断" aria-label="Permalink to &quot;用启发式原则分析事实与推断&quot;">​</a></h1><p>启发式分析使用一组经验性原则检查界面中可能影响任务完成的问题。它适合发现问题线索和组织检查，但不能替代真实行为证据、可访问性标准、业务规则或工程测试。可靠拆解必须把观察事实、原则判断、原因推断和修复建议分开。</p><h2 id="四类记录" tabindex="-1">四类记录 <a class="header-anchor" href="#四类记录" aria-label="Permalink to &quot;四类记录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>定义</th><th>示例</th></tr></thead><tbody><tr><td>事实</td><td>可重复观察或由权威规则确认</td><td>保存请求期间按钮仍可点击，产生两个 POST</td></tr><tr><td>启发式判断</td><td>事实与某条经验原则的关系</td><td>系统状态反馈不足；错误预防不足</td></tr><tr><td>推断</td><td>对原因或影响机制的可证伪解释</td><td>用户可能因无反馈而重复提交</td></tr><tr><td>建议</td><td>基于证据的候选修复</td><td>立即显示忙碌状态；服务端增加幂等保证</td></tr></tbody></table><p>同一事实可以违反多个启发式；同一启发式也能解释多个问题。不要为了填满十条原则重复记录同一个现象。</p><h2 id="分析链" tabindex="-1">分析链 <a class="header-anchor" href="#分析链" aria-label="Permalink to &quot;分析链&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C[&quot;任务、角色与状态&quot;] --&gt; F[&quot;可复现事实&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; H[&quot;启发式分类&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I[&quot;机制与影响推断&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; E[&quot;补充证据或反证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; R[&quot;修复候选&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; V[&quot;完整任务复测&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>启发式不是自然定律。它们帮助提出检查问题，不能单独证明严重度、原因或最佳方案。</p><h2 id="十类常用启发式怎样操作化" tabindex="-1">十类常用启发式怎样操作化 <a class="header-anchor" href="#十类常用启发式怎样操作化" aria-label="Permalink to &quot;十类常用启发式怎样操作化&quot;">​</a></h2><h3 id="系统状态可见" tabindex="-1">系统状态可见 <a class="header-anchor" href="#系统状态可见" aria-label="Permalink to &quot;系统状态可见&quot;">​</a></h3><p>检查动作是否被接收、当前阶段、进度、结果和下一步。异步任务要区分已提交、处理中和最终完成；状态变化要视觉可见并可被辅助技术获知。</p><p>可观察问题：无加载状态、旧数据看似最新、上传完成与处理完成混淆、短暂结果不可再次查看。</p><h3 id="系统与现实匹配" tabindex="-1">系统与现实匹配 <a class="header-anchor" href="#系统与现实匹配" aria-label="Permalink to &quot;系统与现实匹配&quot;">​</a></h3><p>检查对象、动作、顺序和单位是否符合用户任务及业务事实，而不是内部实现。使用“归档”却永久删除，或用内部状态码作为主要文案，都会破坏匹配。</p><h3 id="用户控制与自由" tabindex="-1">用户控制与自由 <a class="header-anchor" href="#用户控制与自由" aria-label="Permalink to &quot;用户控制与自由&quot;">​</a></h3><p>检查返回、取消、退出、撤销和恢复。取消要说明是否停止真实任务；撤销要处理并发和副作用。</p><h3 id="一致性与标准" tabindex="-1">一致性与标准 <a class="header-anchor" href="#一致性与标准" aria-label="Permalink to &quot;一致性与标准&quot;">​</a></h3><p>检查相同功能名称、结果、位置和键盘模式，以及平台原生语义。不同状态需要不同行为时，差异应明确表达。</p><h3 id="错误预防" tabindex="-1">错误预防 <a class="header-anchor" href="#错误预防" aria-label="Permalink to &quot;错误预防&quot;">​</a></h3><p>检查规则是否在操作前可见、危险动作是否可复核、写操作是否幂等、服务端是否保证不变量。前端禁用按钮不是完整预防。</p><h3 id="识别优于回忆" tabindex="-1">识别优于回忆 <a class="header-anchor" href="#识别优于回忆" aria-label="Permalink to &quot;识别优于回忆&quot;">​</a></h3><p>检查是否要求记住前页信息、内部 ID、隐藏规则或不常用格式。提供历史、建议、对象上下文和可见选择，但不要暴露敏感信息或展示无关选项。</p><h3 id="灵活与高效" tabindex="-1">灵活与高效 <a class="header-anchor" href="#灵活与高效" aria-label="Permalink to &quot;灵活与高效&quot;">​</a></h3><p>检查初次用户路径与熟练用户加速器：搜索、最近使用、批量、快捷键和自动化。加速器必须有可见等价路径，快捷键需要避免冲突。</p><h3 id="简洁与相关" tabindex="-1">简洁与相关 <a class="header-anchor" href="#简洁与相关" aria-label="Permalink to &quot;简洁与相关&quot;">​</a></h3><p>检查当前决策所需信息是否突出，无关内容是否干扰。简洁不等于删除风险、规则、状态和恢复信息。</p><h3 id="识别、诊断与恢复错误" tabindex="-1">识别、诊断与恢复错误 <a class="header-anchor" href="#识别、诊断与恢复错误" aria-label="Permalink to &quot;识别、诊断与恢复错误&quot;">​</a></h3><p>错误应指出对象和字段、发生了什么、哪些结果已生效、怎样修正。文本描述不能只靠颜色；输入应尽量保留。</p><h3 id="帮助与文档" tabindex="-1">帮助与文档 <a class="header-anchor" href="#帮助与文档" aria-label="Permalink to &quot;帮助与文档&quot;">​</a></h3><p>检查界面是否能独立完成常见任务，以及复杂规则是否有可搜索、上下文相关的帮助。帮助不能代替修复错误流程，也不能成为唯一的权限与风险说明。</p><h2 id="启发式与规范的边界" tabindex="-1">启发式与规范的边界 <a class="header-anchor" href="#启发式与规范的边界" aria-label="Permalink to &quot;启发式与规范的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>性质</th><th>处理方式</th></tr></thead><tbody><tr><td>Nielsen 启发式</td><td>广泛适用的经验原则</td><td>用于发现与分类潜在问题</td></tr><tr><td>WCAG 成功标准</td><td>Web 可访问性规范要求</td><td>按版本、级别与适用条件评估合规</td></tr><tr><td>WAI-ARIA APG</td><td>信息性组件指导</td><td>用于语义与键盘实现参考，需实际测试</td></tr><tr><td>设计系统</td><td>特定组织的组件与模式约定</td><td>按适用服务和版本使用</td></tr><tr><td>业务规则</td><td>产品与组织定义的确定性约束</td><td>由受控系统执行并验证</td></tr></tbody></table><p>“违反启发式”不等于“违反 WCAG”；通过启发式检查也不等于可访问或可用。</p><h2 id="严重度评估" tabindex="-1">严重度评估 <a class="header-anchor" href="#严重度评估" aria-label="Permalink to &quot;严重度评估&quot;">​</a></h2><p>可使用以下维度分别记录，不急于合成一个分数：</p><ul><li><strong>任务影响</strong>：轻微延迟、可恢复错误、无法完成或错误完成。</li><li><strong>频率</strong>：在明确样本、版本和时间范围内出现多少。</li><li><strong>范围</strong>：影响哪些角色、设备、权限和对象状态。</li><li><strong>可恢复性</strong>：用户能否自行发现并恢复，是否丢数据。</li><li><strong>风险</strong>：资金、隐私、安全、法律和不可逆结果。</li><li><strong>证据强度</strong>：复现、日志、公开反馈或仅为推断。</li></ul><p>严重度不是优先级。优先级还受修复成本、依赖、法规和发布时间影响。</p><h2 id="完整案例-报销提交出现重复记录" tabindex="-1">完整案例：报销提交出现重复记录 <a class="header-anchor" href="#完整案例-报销提交出现重复记录" aria-label="Permalink to &quot;完整案例：报销提交出现重复记录&quot;">​</a></h2><h3 id="上下文与具体事实" tabindex="-1">上下文与具体事实 <a class="header-anchor" href="#上下文与具体事实" aria-label="Permalink to &quot;上下文与具体事实&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>角色：报销申请人</span></span>
<span class="line"><span>对象：报销草稿 R-DRAFT-88</span></span>
<span class="line"><span>设备：移动 Web，弱网 600 ms RTT</span></span>
<span class="line"><span>输入：金额 ¥128，1 张发票</span></span>
<span class="line"><span>完成标准：只创建一个报销记录，并显示编号与待审批状态</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>复现步骤：</p><ol><li>填写草稿并点击“提交”。</li><li>8 秒内按钮无文字、状态或禁用变化。</li><li>第 3 秒再次点击，第 6 秒第三次点击。</li><li>网络面板出现三个 POST，请求体相同且没有幂等键。</li><li>最终出现三个报销编号，页面只显示最后一个“提交成功”Toast。</li></ol><h3 id="事实、原则与推断分离" tabindex="-1">事实、原则与推断分离 <a class="header-anchor" href="#事实、原则与推断分离" aria-label="Permalink to &quot;事实、原则与推断分离&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编号</th><th>类型</th><th>内容</th></tr></thead><tbody><tr><td>F-01</td><td>事实</td><td>首次点击后 8 秒无可见或可感知状态变化</td></tr><tr><td>F-02</td><td>事实</td><td>三次点击产生三个 POST 和三个对象</td></tr><tr><td>F-03</td><td>事实</td><td>结果只显示最后一个编号，其他记录需从列表发现</td></tr><tr><td>H-01</td><td>启发式</td><td>系统状态可见、错误预防和结果恢复存在问题</td></tr><tr><td>I-01</td><td>推断</td><td>无反馈提高重复点击可能性；需要行为数据或观察补证</td></tr><tr><td>I-02</td><td>推断</td><td>服务端没有幂等约束；由请求结果支持，仍需检查实现规则</td></tr></tbody></table><h3 id="修复方案" tabindex="-1">修复方案 <a class="header-anchor" href="#修复方案" aria-label="Permalink to &quot;修复方案&quot;">​</a></h3><ol><li>点击后立即把按钮进入明确忙碌状态，并阻止界面重复发起同一意图。</li><li>客户端为一次提交意图生成幂等键，服务端以用户、草稿和键保证重复请求返回同一结果。</li><li>结果使用持久页面，显示报销编号、金额、状态和下一步。</li><li>超时结果未知时，按幂等键查询，而不是生成新意图。</li><li>已生成的重复记录需要安全的清理或撤销路径，并保留审计。</li></ol><h3 id="可观察输出" tabindex="-1">可观察输出 <a class="header-anchor" href="#可观察输出" aria-label="Permalink to &quot;可观察输出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提交中：报销草稿 R-DRAFT-88</span></span>
<span class="line"><span>提交结果：报销 R-2041 已创建</span></span>
<span class="line"><span>状态：待审批</span></span>
<span class="line"><span>重复请求结果：仍返回 R-2041，不创建新记录</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><ul><li>服务端创建成功但响应丢失：客户端用相同键重试并取得 R-2041。</li><li>校验失败：保留草稿，定位金额或发票错误，不创建对象。</li><li>权限被撤销：服务端拒绝，页面说明未提交且保留本地输入。</li><li>状态消息只视觉显示：屏幕阅读器无法获知，需使用适当程序语义。</li></ul><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ol><li>连续点击、网络重放和多标签页发送相同幂等键，只产生一个记录。</li><li>在 200 ms、8 秒和超时三种延迟下检查忙碌与未知结果。</li><li>仅用键盘提交，焦点不丢失且结果可感知。</li><li>刷新与重新登录后，结果页和列表显示同一记录。</li><li>对照 WCAG 状态消息与错误要求，不把启发式结论当作合规证明。</li></ol><h2 id="可复制问题模板" tabindex="-1">可复制问题模板 <a class="header-anchor" href="#可复制问题模板" aria-label="Permalink to &quot;可复制问题模板&quot;">​</a></h2><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 问题标题</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 上下文：角色、任务、版本、设备、数据状态</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 复现步骤：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 预期结果：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 实际事实：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 证据编号：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 相关启发式：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 相关规范或业务规则：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 原因推断：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 反证条件/未知项：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 用户与业务影响：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 修复候选：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 验证步骤与通过标准：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="多人检查与去重" tabindex="-1">多人检查与去重 <a class="header-anchor" href="#多人检查与去重" aria-label="Permalink to &quot;多人检查与去重&quot;">​</a></h2><p>不同检查者会发现不同问题。合并结果时按“同一触发条件、同一机制、同一影响”去重；一个问题可标多个原则，但保留一个事实记录。分歧应回到可复现证据，不用原则名称投票。</p><p>个人学习没有多人条件时，可在不同时间、角色和输入方式下重复检查，并把首次结论隐藏后重新执行，降低记忆影响，但仍不能声称覆盖了真实用户行为。</p><h2 id="常见错误与修正" tabindex="-1">常见错误与修正 <a class="header-anchor" href="#常见错误与修正" aria-label="Permalink to &quot;常见错误与修正&quot;">​</a></h2><ul><li>为每条启发式强行找问题：只记录有证据的现象。</li><li>把原则名称当事实：“不一致”要说明哪里、怎样不同。</li><li>从一个截图推断用户一定失败：补任务观察和交互证据。</li><li>给出修复方案却不写机制和验证标准。</li><li>用启发式代替 WCAG、权限、安全或性能测试。</li><li>将多个相同根因拆成十条重复问题。</li><li>只报告数量和严重度，不保存复现与证据。</li><li>认为没有发现问题等于界面可用。</li></ul><h2 id="可执行分析步骤" tabindex="-1">可执行分析步骤 <a class="header-anchor" href="#可执行分析步骤" aria-label="Permalink to &quot;可执行分析步骤&quot;">​</a></h2><ol><li>固定角色、任务、版本、设备、数据与完成标准。</li><li>先完整执行任务，记录动作、状态和证据。</li><li>第二遍按启发式逐项检查，但不强行填充。</li><li>把记录拆为事实、原则判断、推断和建议。</li><li>对涉及键盘、状态、错误等问题对照 WCAG 与平台规范。</li><li>用日志、请求、公开反馈或故障注入验证原因推断。</li><li>评估任务影响、范围、恢复、风险和证据强度。</li><li>去重后写修复候选，并在完整任务与边界状态复测。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>对一个“账户安全设置”流程进行启发式分析。</p><p>完成时应满足：</p><ul><li>固定普通用户和管理员两个角色及明确任务；</li><li>至少记录 8 条可复现事实，不要求覆盖每条启发式；</li><li>每条事实与启发式判断、原因推断分开；</li><li>涉及认证、错误、焦点和状态时引用适用标准或规则；</li><li>严重度按任务影响、范围、恢复和风险说明；</li><li>修复方案覆盖主路径、失败、键盘和权限；</li><li>复测报告能说明问题是否真实消失，而不是只检查画面变化。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.nngroup.com/articles/ten-usability-heuristics/" target="_blank" rel="noreferrer">Jakob Nielsen：10 Usability Heuristics for User Interface Design</a>（访问日期：2026-07-17）</li><li><a href="https://www.nngroup.com/articles/how-to-conduct-a-heuristic-evaluation/" target="_blank" rel="noreferrer">Jakob Nielsen：How to Conduct a Heuristic Evaluation</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C：Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/about/introduction/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Introduction</a>（访问日期：2026-07-17）</li></ul>`,67)])])}const u=s(e,[["render",l]]);export{b as __pageData,u as default};
